1	// claim-office.ts
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Item = {
5	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const INSURANCE_SURCHARGE_RATE = 0.1;
13	const RUNE_BLOCK_SIZE = 3;
14	const RUNE_BLOCK_PRICE = 60;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	export function quote(_customer: Customer, items: Item[]): number {
26	  const runeCount = items.filter((i) => i.type === "rune").length;
27	  const runeBase =
28	    runeCount === RUNE_BLOCK_SIZE
29	      ? RUNE_BLOCK_PRICE
30	      : runeCount * BASE_PREMIUMS.rune;
31	  const nonRuneBase = items
32	    .filter((i) => i.type !== "rune")
33	    .reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
34	  const itemsBase = nonRuneBase + runeBase;
35	  const insuranceSurcharge = itemsBase * INSURANCE_SURCHARGE_RATE;
36	  return Math.ceil(itemsBase + insuranceSurcharge + PROCESSING_FEE);
37	}
