74	  it.todo("quote with cursed sword adds 50% surcharge on item base premium (100 + 50 curse)");
75	  it.todo("quote with sword at enchantment 5 adds 30% surcharge on item base premium");
76	  it.todo("quote with sword at enchantment 4 does not add high-enchantment surcharge");
77	  it.todo("quote with cursed sword at enchantment 5 stacks both surcharges");
78	
79	  // Modifier scope on multi-item policies
80	  it.todo("quote with cursed sword + plain amulet applies curse only to sword's base premium (210 before policy modifiers and fee)");
81	
82	  // Policy-wide modifiers
83	  it.todo("quote with customer at exactly 2 years applies 20% loyalty discount on policy total");
84	  it.todo("quote with customer at less than 2 years does not apply loyalty discount");
85	  it.todo("quote first insurance adds 10% surcharge per item on the policy");
86	  it.todo("quote follow-up contract (after first quote in scenario) applies 15% discount on policy total");
87	
88	  // Rounding
89	  it.todo("premium calculation yielding 197.5 rounds up to 198");
90	
91	  // Integration examples from spec
92	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) returns premium 165");
93	  it.todo("long-standing customer's second contract: cursed sword (enchantment 7, 3 years, 2nd quote) returns premium 160");
94	
95	  // Quote: error cases
96	  it.todo("quote with unknown item type causes CLI to exit non-zero with error to stderr");
97	
98	  // Claim: basic payouts
99	  it.todo("claim on regular sword (steel, enchantment 3) with damage 500 returns payout 400 (full reimbursement minus 100 deductible)");
100	  it.todo("claim on rune (insurance value 250) with damage 200 returns payout 100 (full reimbursement minus 100 deductible)");
101	
102	  // Claim: enchantment threshold
103	  it.todo("claim on steel sword enchantment 9 with damage 1000 returns payout 400 (50% reimbursement, then 100 deductible)");
104	
105	  // Claim: dragon material
106	  it.todo("claim on dragon-material sword enchantment 5 with damage 800 returns payout 700 (full reimbursement, then 100 deductible)");
107	  it.todo("claim on dragon-material sword enchantment 9 with damage 1000 returns payout 400 (50% rule wins, then deductible)");
108	  it.todo("claim on dragon-material sword enchantment 8 with damage 1000 returns payout 400 (high-enchantment clause applies, then deductible)");
109	
110	  // Claim: deductible per damage event
111	  it.todo("claim with two damaged items (sword 500 + amulet 300) applies deductible per item: payout 600");
112	
113	  // Claim: multiple items of the same type
114	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
115	  it.todo("claim with two sword damages on a two-sword policy treats each as separate damage with own deductible");
116	  it.todo("claim with more sword damages than swords insured causes CLI to exit non-zero");
117	
118	  // Claim: cap
119	  it.todo("policy with sword + amulet has insurance sum 1600 and cap 3200");
120	  it.todo("policy with sword + 3 runes has insurance sum 1750 (block discount affects premium only, not cap)");
121	  it.todo("cap is based on unmodified insurance value (cursed sword cap = 2000)");
122	  it.todo("first claim of 1500 on sword (cap 2000) returns payout 1400 with remainingCap 600");
123	  it.todo("second claim of 1500 with remainingCap 600 returns payout 600 with remainingCap 0");
124	
125	  // Claim: rounding
126	  it.todo("payout calculation yielding 350.5 rounds down to 350");
127	
128	  // Claim: error cases
129	  it.todo("claim referencing item not in policy causes CLI to exit non-zero with error to stderr");
130	  it.todo("claim with negative damage amount causes CLI to exit non-zero with error to stderr");
131	
132	  // CLI integration
